// ── 通道選擇（全域，同步 localStorage）──
function getChannel() {
  try { return localStorage.getItem("ai-channel") || "free"; } catch { return "free"; }
}
function setChannel(c) {
  try { localStorage.setItem("ai-channel", c); } catch {}
}

// ── AI 分析呼叫（經後端代理，帶登入 token）──
async function callAI(prompt, channel, kind) {
  const token = await getToken();
  if (!token) throw new Error("未登入，請重新整理頁面");
  const resp = await fetch("/api/analyze", {
    method: "POST",
    headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
    body: JSON.stringify({ prompt, channel, kind })
  });
  if (!resp.ok) {
    let msg = "分析服務異常";
    try { const e = await resp.json(); msg = e.error || msg; } catch {}
    throw new Error(msg);
  }
  const data = await resp.json();
  return data.text || "分析完成但無內容返回";
}


