const TIAN_GAN = ["甲","乙","丙","丁","戊","己","庚","辛","壬","癸"];
const DI_ZHI = ["子","丑","寅","卯","辰","巳","午","未","申","酉","戌","亥"];
const WU_XING = ["木","木","火","火","土","土","金","金","水","水"];
const ZHI_WX = ["水","土","木","木","土","火","火","土","金","金","土","水"];
const SIXTY = Array.from({length:60},(_,i)=>TIAN_GAN[i%10]+DI_ZHI[i%12]);
const GAN_IDX = g => TIAN_GAN.indexOf(g);
const ZHI_IDX = z => DI_ZHI.indexOf(z);
const GZ_IDX = (g,z) => { for(let i=0;i<60;i++) if(i%10===g && i%12===z) return i; return -1; };

// 五行生剋
const WX_SHENG = {木:"火",火:"土",土:"金",金:"水",水:"木"};
const WX_KE = {木:"土",火:"金",土:"水",金:"木",水:"火"};
const wxOf = g => typeof g==="number" ? WU_XING[g] : WU_XING[GAN_IDX(g)];
const zhiWx = z => typeof z==="number" ? ZHI_WX[z] : ZHI_WX[ZHI_IDX(z)];

