const ZHI_CHONG = {}; for(let i=0;i<12;i++) ZHI_CHONG[DI_ZHI[i]]=DI_ZHI[(i+6)%12];
function xingOrChong(zhi) { const x=ZHI_XING[zhi]; return x===zhi?ZHI_CHONG[zhi]:x; }

