// 十神
function tenGod(dayGan, otherGan) {
  const me = wxOf(dayGan), other = wxOf(otherGan);
  const meYin = (typeof dayGan==="number"?dayGan:GAN_IDX(dayGan))%2;
  const otYin = (typeof otherGan==="number"?otherGan:GAN_IDX(otherGan))%2;
  const same = meYin===otYin;
  if(me===other) return same?"比肩":"劫財";
  if(WX_SHENG[me]===other) return same?"食神":"傷官";
  if(WX_KE[me]===other) return same?"偏財":"正財";
  if(WX_KE[other]===me) return same?"七殺":"正官";
  if(WX_SHENG[other]===me) return same?"偏印":"正印";
  return "";
}

// ═══════════════════════════════════════════════════════
// 節氣 / 太陽黃經計算（共用）
// ═══════════════════════════════════════════════════════
function jdFromDate(y,m,d,h=0,mi=0,s=0) {
  const a=Math.floor((14-m)/12), yy=y+4800-a, mm=m+12*a-3;
  let jd=d+Math.floor((153*mm+2)/5)+365*yy+Math.floor(yy/4)-Math.floor(yy/100)+Math.floor(yy/400)-32045;
  jd += (h-12)/24+mi/1440+s/86400;
  return jd;
}
function solarLongitude(jd) {
  const T=(jd-2451545)/36525;
  let L0=280.46646+36000.76983*T+0.0003032*T*T;
  let M=357.52911+35999.05029*T-0.0001537*T*T;
  const Mr=M*Math.PI/180;
  const C=(1.914602-0.004817*T)*Math.sin(Mr)+(0.019993-0.000101*T)*Math.sin(2*Mr)+0.000289*Math.sin(3*Mr);
  let sun=L0+C; const Om=125.04-1934.136*T;
  sun=sun-0.00569-0.00478*Math.sin(Om*Math.PI/180);
  return ((sun%360)+360)%360;
}
function findJieqi(year, targetLon, startMonth=1) {
  const jd0=jdFromDate(year,Math.max(1,startMonth),1)-15;
  let prevDiff=null, lo=jd0, hi=jd0;
  for(let d=0;d<120;d++){
    const jd=jd0+d;
    let sl=solarLongitude(jd);
    let diff=sl-targetLon; if(diff>180)diff-=360; if(diff<-180)diff+=360;
    if(prevDiff!==null && prevDiff<0 && diff>=0){ lo=jd-1; hi=jd; break; }
    prevDiff=diff;
  }
  if(lo===hi) return jd0+30;
  for(let i=0;i<60;i++){
    const mid=(lo+hi)/2;
    let sl=solarLongitude(mid);
    let diff=sl-targetLon; if(diff>180)diff-=360; if(diff<-180)diff+=360;
    if(diff<0) lo=mid; else hi=mid;
  }
  return (lo+hi)/2;
}
// 24節氣黃經度
const JIEQI_NAMES = ["小寒","大寒","立春","雨水","驚蟄","春分","清明","穀雨","立夏","小滿","芒種","夏至","小暑","大暑","立秋","處暑","白露","秋分","寒露","霜降","立冬","小雪","大雪","冬至"];
const JIEQI_LON = [285,300,315,330,345,0,15,30,45,60,75,90,105,120,135,150,165,180,195,210,225,240,255,270];

function getJieqiDates(year) {
  // Each jieqi's approximate month: [name, longitude, searchYear offset, startMonth]
  const jqMap = [
    ["小寒",285,0,1],["大寒",300,0,1],["立春",315,0,1],["雨水",330,0,2],
    ["驚蟄",345,0,2],["春分",0,0,3],["清明",15,0,3],["穀雨",30,0,4],
    ["立夏",45,0,4],["小滿",60,0,5],["芒種",75,0,5],["夏至",90,0,6],
    ["小暑",105,0,6],["大暑",120,0,7],["立秋",135,0,7],["處暑",150,0,8],
    ["白露",165,0,8],["秋分",180,0,9],["寒露",195,0,9],["霜降",210,0,10],
    ["立冬",225,0,10],["小雪",240,0,11],["大雪",255,0,11],["冬至",270,0,12]
  ];
  const result = [];
  for(const [name, lon, yOff, sm] of jqMap) {
    const sy = year + yOff;
    const jd = findJieqi(sy, lon, Math.max(1, sm-1 || 1));
    const dt = jdToDate(jd + 0.5/24);
    result.push({name, lon, jd, date:dt});
  }
  return result.sort((a,b)=>a.jd-b.jd);
}
function jdToDate(jd) {
  const z=Math.floor(jd+0.5); const a=z<2299161?z:z+1+Math.floor((z-1867216.25)/36524.25)-Math.floor((z-1867216.25)/36524.25/4);
  const b=a+1524; const c=Math.floor((b-122.1)/365.25); const d=Math.floor(365.25*c); const e=Math.floor((b-d)/30.6001);
  const day=b-d-Math.floor(30.6001*e); const mon=e<14?e-1:e-13; const yr=mon>2?c-4716:c-4715;
  const frac=(jd+0.5)-z; const hh=frac*24; const h=Math.floor(hh); const mm=(hh-h)*60; const m=Math.floor(mm);
  return new Date(yr,mon-1,day,h,m);
}

// 日柱計算（2000-01-07 = 甲子日 作基準）
function dayPillarIndex(y,m,d) {
  const ref = new Date(2000,0,7); const target = new Date(y,m-1,d);
  const diff = Math.round((target-ref)/86400000);
  return ((diff%60)+60)%60;
}

// 年柱（立春換年）
function yearPillar(y, m, d, jieqiDates) {
  const cur = new Date(y,m-1,d);
  // Find the most recent 立春 before or on current date
  const lichunList = jieqiDates.filter(j=>j.name==="立春").sort((a,b)=>b.jd-a.jd);
  let lunarY = y;
  for(const lc of lichunList) {
    if(cur >= lc.date) { lunarY = lc.date.getFullYear(); break; }
    lunarY = lc.date.getFullYear() - 1;
  }
  return ((lunarY-4)%60+60)%60;
}

// 月柱（節氣定月）
const JIE = ["立春","驚蟄","清明","立夏","芒種","小暑","立秋","白露","寒露","立冬","大雪","小寒"];
const JIE_MONTH = {立春:1,驚蟄:2,清明:3,立夏:4,芒種:5,小暑:6,立秋:7,白露:8,寒露:9,立冬:10,大雪:11,小寒:12};
function monthPillar(y,m,d, jieqiDates) {
  const cur = new Date(y,m-1,d);
  // Collect all 節 dates and sort descending
  const jieEntries = [];
  for(const jieName of JIE) {
    const matches = jieqiDates.filter(j=>j.name===jieName);
    for(const jq of matches) jieEntries.push({name:jieName, date:jq.date, monthNum:JIE_MONTH[jieName]});
  }
  jieEntries.sort((a,b)=>b.date-a.date);
  let monthNum = 12;
  for(const entry of jieEntries) {
    if(cur >= entry.date) { monthNum = entry.monthNum; break; }
  }
  if(monthNum===0) monthNum=12;
  const yearGanIdx = yearPillar(y,m,d,jieqiDates)%10;
  const monthGanBase = (yearGanIdx%5)*2;
  const ganIdx = (monthGanBase + monthNum + 1) % 10;
  const zhiIdx = (monthNum + 1) % 12;
  return GZ_IDX(ganIdx, zhiIdx);
}

// 時柱（五鼠遁）
function hourPillar(dayGanIdx, hour) {
  const zhiIdx = Math.floor((hour+1)/2)%12;
  const base = (dayGanIdx%5)*2;
  const ganIdx = (base + zhiIdx) % 10;
  return GZ_IDX(ganIdx, zhiIdx);
}

// ═══════════════════════════════════════════════════════
// 八字引擎
// ═══════════════════════════════════════════════════════
function calcBazi(y,m,d,h,mi=0,lng=121.5) {
  const correction = (lng-120)*4;
  const totalMin = h*60+mi+correction;
  const adjH = Math.floor(((totalMin%1440)+1440)%1440/60);
  const adjD = totalMin<0?d-1:totalMin>=1440?d+1:d;
  const jq = getJieqiDates(y);
  const jqPrev = y>1900?getJieqiDates(y-1):jq;
  const allJq = [...jqPrev,...jq,...getJieqiDates(y+1)].sort((a,b)=>a.jd-b.jd);
  const dayIdx = dayPillarIndex(y,m,adjD<1?d:adjD>28?d:adjD);
  const yearIdx = yearPillar(y,m,d,allJq);
  const monthIdx = monthPillar(y,m,d,allJq);
  const hourIdx = hourPillar(dayIdx%10, adjH);
  const dayGan = TIAN_GAN[dayIdx%10];
  const shensha = calcShensha(dayIdx, yearIdx, monthIdx, hourIdx);
  const shenshaDetail = calcShenshaDetail(dayIdx, yearIdx, monthIdx, hourIdx);
  return {
    year:{gz:SIXTY[yearIdx],gan:TIAN_GAN[yearIdx%10],zhi:DI_ZHI[yearIdx%12],idx:yearIdx},
    month:{gz:SIXTY[monthIdx],gan:TIAN_GAN[monthIdx%10],zhi:DI_ZHI[monthIdx%12],idx:monthIdx},
    day:{gz:SIXTY[dayIdx],gan:dayGan,zhi:DI_ZHI[dayIdx%12],idx:dayIdx},
    hour:{gz:SIXTY[hourIdx],gan:TIAN_GAN[hourIdx%10],zhi:DI_ZHI[hourIdx%12],idx:hourIdx},
    dayGan, shensha, shenshaDetail, jieqi: allJq, trueSolarH: adjH
  };
}

