const CS_START = {甲:11,乙:6,丙:2,丁:9,戊:2,己:9,庚:5,辛:0,壬:8,癸:3};
function getChangSheng(dayGan, zhi) {
  const s = CS_START[dayGan]; const zi = ZHI_IDX(zhi);
  const isYang = GAN_IDX(dayGan)%2===0;
  const diff = isYang ? ((zi-s)%12+12)%12 : ((s-zi)%12+12)%12;
  return CS_NAMES[diff];
}
