const ZHI_SANHE = {寅:["寅","午","戌"],午:["寅","午","戌"],戌:["寅","午","戌"],申:["申","子","辰"],子:["申","子","辰"],辰:["申","子","辰"],巳:["巳","酉","丑"],酉:["巳","酉","丑"],丑:["巳","酉","丑"],亥:["亥","卯","未"],卯:["亥","卯","未"],未:["亥","卯","未"]};
const ZHI_CHONG_MAP = {子:"午",午:"子",丑:"未",未:"丑",寅:"申",申:"寅",卯:"酉",酉:"卯",辰:"戌",戌:"辰",巳:"亥",亥:"巳"};
