const ZHI_PO = {子:"酉",酉:"子",丑:"辰",辰:"丑",寅:"亥",亥:"寅",卯:"午",午:"卯",巳:"申",申:"巳",未:"戌",戌:"未"};

function analyzeGanZhiRelations(bazi) {
  const relations = [];
  const pillars = [{n:"年",g:bazi.year.gan,z:bazi.year.zhi},{n:"月",g:bazi.month.gan,z:bazi.month.zhi},{n:"日",g:bazi.day.gan,z:bazi.day.zhi},{n:"時",g:bazi.hour.gan,z:bazi.hour.zhi}];
  for(let i=0;i<4;i++) for(let j=i+1;j<4;j++){
    const a=pillars[i], b=pillars[j];
    if(GAN_HE[a.g]===b.g) relations.push({type:"天干合",desc:a.n+a.g+"合"+b.n+b.g,color:"#2a7a3a"});
    if(GAN_CHONG[a.g]===b.g) relations.push({type:"天干沖",desc:a.n+a.g+"沖"+b.n+b.g,color:"#c23b22"});
    if(ZHI_LIUHE[a.z]===b.z) relations.push({type:"地支六合",desc:a.n+a.z+"合"+b.n+b.z,color:"#2a7a3a"});
    if(ZHI_CHONG_MAP[a.z]===b.z) relations.push({type:"地支沖",desc:a.n+a.z+"沖"+b.n+b.z,color:"#c23b22"});
    if(ZHI_HAI[a.z]===b.z) relations.push({type:"地支害",desc:a.n+a.z+"害"+b.n+b.z,color:"#996600"});
    if(ZHI_XING[a.z]===b.z) relations.push({type:"地支刑",desc:a.n+a.z+"刑"+b.n+b.z,color:"#b22222"});
    if(ZHI_PO[a.z]===b.z) relations.push({type:"地支破",desc:a.n+a.z+"破"+b.n+b.z,color:"#8a5a2a"});
  }
  // 三合局
  const zhis = pillars.map(p=>p.z);
  for(const elem of ["寅","申","巳","亥"]){
    const group = ZHI_SANHE[elem];
    const matched = group.filter(z=>zhis.includes(z));
    if(matched.length>=3) relations.push({type:"三合局",desc:matched.join("")+"三合",color:"#3d7a6a"});
  }
  // 三會局
  const sanHui = [["寅","卯","辰","木"],["巳","午","未","火"],["申","酉","戌","金"],["亥","子","丑","水"]];
  for(const [a,b,c,wx] of sanHui) {
    if(zhis.includes(a)&&zhis.includes(b)&&zhis.includes(c)) relations.push({type:"三會局",desc:a+b+c+"三會"+wx,color:"#228B22"});
  }
  return relations;
}

// 大運（改良版：計算起運歲數）
function calcDayun(bazi, gender, birthDate) {
  const yearGan = bazi.year.idx%10;
  const isYang = yearGan%2===0;
  const isMale = gender==="男";
  const forward = (isYang&&isMale)||(!isYang&&!isMale);
  // 計算起運歲數
  let startAge = 1;
  try {
    const [by,bm,bd] = birthDate.split("-").map(Number);
    const birthObj = new Date(by,bm-1,bd);
    const allJq = [...getJieqiDates(by-1),...getJieqiDates(by),...getJieqiDates(by+1)].sort((a,b)=>a.jd-b.jd);
    const jieOnly = allJq.filter(j=>JIE.includes(j.name));
    let targetJie;
    if(forward) { targetJie = jieOnly.find(j=>j.date>birthObj); }
    else { const before = jieOnly.filter(j=>j.date<=birthObj); targetJie = before[before.length-1]; }
    if(targetJie) { const days = Math.abs(Math.round((targetJie.date-birthObj)/86400000)); startAge = Math.round(days/3); }
  } catch(e) { startAge = 1; }
  if(startAge<1) startAge=1;
  const monthGanIdx = bazi.month.idx%10;
  const monthZhiIdx = bazi.month.idx%12;
  const dayun = [];
  for(let i=1;i<=8;i++){
    const gIdx = forward?(monthGanIdx+i)%10:(monthGanIdx-i+100)%10;
    const zIdx = forward?(monthZhiIdx+i)%12:(monthZhiIdx-i+120)%12;
    const age = startAge + (i-1)*10;
    dayun.push({gan:TIAN_GAN[gIdx],zhi:DI_ZHI[zIdx],gz:TIAN_GAN[gIdx]+DI_ZHI[zIdx],startAge:age,endAge:age+9,tenGod:tenGod(bazi.dayGan,TIAN_GAN[gIdx])});
  }
  return dayun;
}

