// 大六壬引擎
// ═══════════════════════════════════════════════════════
const LIU_REN_JIEQI_YUEJIANG = {"雨水":"亥","春分":"戌","穀雨":"酉","小滿":"申","夏至":"未","大暑":"午","處暑":"巳","秋分":"辰","霜降":"卯","小雪":"寅","冬至":"丑","大寒":"子"};
const ZHONGSHEN = ["雨水","春分","穀雨","小滿","夏至","大暑","處暑","秋分","霜降","小雪","冬至","大寒"];

function getYueJiang(jieqiDates, date) {
  let current = "丑";
  const zhongqi = jieqiDates.filter(j=>ZHONGSHEN.includes(j.name)).sort((a,b)=>a.jd-b.jd);
  for(const zq of zhongqi) {
    if(date >= zq.date) current = LIU_REN_JIEQI_YUEJIANG[zq.name];
  }
  return current;
}

// 天地盤
function buildTianDiPan(yueJiang, shiZhi) {
  const yjIdx = ZHI_IDX(yueJiang);
  const szIdx = ZHI_IDX(shiZhi);
  const shift = ((yjIdx - szIdx)%12+12)%12;
  const tianPan = {};
  for(let i=0;i<12;i++){
    const diPanZhi = DI_ZHI[i];
    const tianPanIdx = (i+shift)%12;
    tianPan[diPanZhi] = DI_ZHI[tianPanIdx];
  }
  return tianPan;
}

// 四課
function buildSiKe(dayGan, dayZhi, tianPan) {
  const ganJiGong = {甲:"寅",乙:"辰",丙:"巳",丁:"未",戊:"巳",己:"未",庚:"申",辛:"戌",壬:"亥",癸:"丑"};
  const ganGong = ganJiGong[dayGan];
  const k1shang = tianPan[ganGong];
  const k1xia = ganGong;
  const k2shang = tianPan[k1shang];
  const k2xia = k1shang;
  const k3shang = tianPan[dayZhi];
  const k3xia = dayZhi;
  const k4shang = tianPan[k3shang];
  const k4xia = k3shang;
  return [
    {shang:k1shang,xia:k1xia,label:"一課"},
    {shang:k2shang,xia:k2xia,label:"二課"},
    {shang:k3shang,xia:k3xia,label:"三課"},
    {shang:k4shang,xia:k4xia,label:"四課"}
  ];
}

// 五行剋判斷（支對支）
function wxKe(a,b) { return WX_KE[zhiWx(a)]===zhiWx(b); }
// 元素級剋判斷
function wxKeE(ea,eb) { return WX_KE[ea]===eb; }

// 十干寄宮 / 各支所寄天干
const GAN_JI_GONG = {甲:"寅",乙:"辰",丙:"巳",丁:"未",戊:"巳",己:"未",庚:"申",辛:"戌",壬:"亥",癸:"丑"};
const JI_GONG_STEMS = {寅:["甲"],辰:["乙"],巳:["丙","戊"],未:["丁","己"],申:["庚"],戌:["辛"],亥:["壬"],丑:["癸"]};
// 三合驛馬（按日支）
const SANHE_YIMA = {申:"寅",子:"寅",辰:"寅",寅:"申",午:"申",戌:"申",巳:"亥",酉:"亥",丑:"亥",亥:"巳",卯:"巳",未:"巳"};

// 涉害深度：自所臨地盤位順歷至本家，計克數（含寄宮干）
// shangKe=false: 下賊上候選，計「受克」；shangKe=true: 上克下候選，計「所克」
function sheHaiDepth(shang, sitPos, shangKe) {
  const wx = zhiWx(shang);
  let cnt=0, pos=ZHI_IDX(sitPos); const home=ZHI_IDX(shang); let g=0;
  while(pos!==home && g++<12){
    const br=DI_ZHI[pos];
    if(shangKe){
      if(wxKeE(wx, zhiWx(br))) cnt++;
      for(const st of (JI_GONG_STEMS[br]||[])) if(wxKeE(wx, wxOf(st))) cnt++;
    } else {
      if(wxKeE(zhiWx(br), wx)) cnt++;
      for(const st of (JI_GONG_STEMS[br]||[])) if(wxKeE(wxOf(st), wx)) cnt++;
    }
    pos=(pos+1)%12;
  }
  return cnt;
}

// 九宗門取三傳（正宗）
function getSanChuan(siKe, tianPan, dayGan, dayZhi) {
  const isYang = GAN_IDX(dayGan)%2===0;
  const ganGong = GAN_JI_GONG[dayGan];
  const ganShang = tianPan[ganGong];   // 干上神
  const zhiShang = tianPan[dayZhi];    // 支上神
  const dayWx = wxOf(dayGan);
  const T = z => tianPan[z];
  // 課1下為日干本身（克判斷用日干五行，非寄宮支）
  const keList = siKe.map((k,i)=>({...k,idx:i,xiaWx:i===0?dayWx:zhiWx(k.xia),sitPos:i===0?ganGong:k.xia}));

  // ===== 伏吟 =====
  if(DI_ZHI.every(z=>tianPan[z]===z)) {
    const zk = keList.filter(k=>wxKeE(k.xiaWx, zhiWx(k.shang)));
    const sk = keList.filter(k=>wxKeE(zhiWx(k.shang), k.xiaWx));
    let chu;
    if(zk.length>=1) chu = zk[0].shang;
    else if(sk.length>=1) chu = sk[0].shang;
    else chu = isYang ? ganShang : zhiShang;  // 自任/自信
    let zhong;
    if(ZHI_XING[chu]!==chu) zhong = ZHI_XING[chu];
    else zhong = isYang ? zhiShang : ganShang;  // 初自刑：陽取支上，陰取干上
    let mo;
    if(ZHI_XING[zhong]!==zhong && ZHI_XING[zhong]!==chu) mo = ZHI_XING[zhong];
    else mo = ZHI_CHONG[zhong];  // 中自刑取沖
    return {chu, zhong, mo, method:"伏吟"};
  }

  const isFanYin = DI_ZHI.every(z=>ZHI_IDX(tianPan[z])===(ZHI_IDX(z)+6)%12);
  const finish = (chu, method) => ({chu, zhong:T(chu), mo:T(T(chu)), method:isFanYin?method+"・反吟":method});

  // 比用→涉害
  const biSheHai = (cands, shangKe) => {
    const bi = cands.filter(k=>ZHI_IDX(k.shang)%2===GAN_IDX(dayGan)%2);
    if(bi.length===1) return finish(bi[0].shang, "比用法");
    const pool = bi.length>1 ? bi : cands;
    const depths = pool.map(c=>({c, d:sheHaiDepth(c.shang, c.sitPos, shangKe)}));
    const maxD = Math.max(...depths.map(x=>x.d));
    const ties = depths.filter(x=>x.d===maxD).map(x=>x.c);
    if(ties.length===1) return finish(ties[0].shang, "涉害法");
    // 涉害相等：取孟→仲→復等
    const MENG=["寅","申","巳","亥"], ZHNG=["子","午","卯","酉"];
    const meng = ties.filter(c=>MENG.includes(c.sitPos));
    if(meng.length>=1) return finish(meng[0].shang, "涉害法（取孟）");
    const zh = ties.filter(c=>ZHNG.includes(c.sitPos));
    if(zh.length>=1) return finish(zh[0].shang, "涉害法（取仲）");
    return finish(isYang?ganShang:zhiShang, "涉害法（復等）");
  };

  // ===== 賊克 =====
  const zk = keList.filter(k=>wxKeE(k.xiaWx, zhiWx(k.shang)));  // 下賊上
  if(zk.length===1) return finish(zk[0].shang, "賊克法（重審）");
  if(zk.length>1) return biSheHai(zk, false);
  const sk = keList.filter(k=>wxKeE(zhiWx(k.shang), k.xiaWx));  // 上克下
  if(sk.length===1) return finish(sk[0].shang, "賊克法（元首）");
  if(sk.length>1) return biSheHai(sk, true);

  // ===== 無克 =====
  // 反吟無克（丑未日）：驛馬發用，中支上，末干上
  if(isFanYin){
    return {chu:SANHE_YIMA[dayZhi], zhong:zhiShang, mo:ganShang, method:"反吟（驛馬）"};
  }
  // 八專（干支同宮：甲寅丁未己未庚申癸丑）
  if(ganGong===dayZhi){
    if(isYang){
      const chu = DI_ZHI[(ZHI_IDX(ganShang)+2)%12];  // 干上神順數三位
      return {chu, zhong:ganShang, mo:ganShang, method:"八專"};
    } else {
      const k4 = keList[3].shang;
      const chu = DI_ZHI[(ZHI_IDX(k4)-2+12)%12];      // 第四課上神逆數三位
      return {chu, zhong:ganShang, mo:ganShang, method:"八專"};
    }
  }
  // ===== 遙克（二三四課上神 vs 日干）=====
  const rest = keList.filter(k=>k.idx>0);
  let yao = rest.filter(k=>wxKeE(zhiWx(k.shang), dayWx));  // 蒿矢
  let ym = "遙克（蒿矢）";
  if(yao.length===0){ yao = rest.filter(k=>wxKeE(dayWx, zhiWx(k.shang))); ym="遙克（彈射）"; }
  if(yao.length>=1){
    if(yao.length===1) return finish(yao[0].shang, ym);
    const bi = yao.filter(k=>ZHI_IDX(k.shang)%2===GAN_IDX(dayGan)%2);
    return finish((bi[0]||yao[0]).shang, ym);
  }
  // ===== 昴星（四課全備無克無遙）=====
  const distinct = new Set(siKe.map(k=>k.shang+"/"+k.xia));
  if(distinct.size===4){
    if(isYang){
      return {chu:tianPan["酉"], zhong:zhiShang, mo:ganShang, method:"昴星（虎視）"};
    } else {
      let below="酉"; for(const z of DI_ZHI){ if(tianPan[z]==="酉"){below=z;break;} }
      return {chu:below, zhong:ganShang, mo:zhiShang, method:"昴星（冬蛇掩目）"};
    }
  }
  // ===== 別責（三課備）=====
  if(isYang){
    const chu = tianPan[GAN_JI_GONG[GAN_HE[dayGan]]];  // 干合寄宮上神
    return {chu, zhong:ganShang, mo:ganShang, method:"別責"};
  } else {
    const chu = DI_ZHI[(ZHI_IDX(dayZhi)+4)%12];         // 支三合前辰
    return {chu, zhong:ganShang, mo:ganShang, method:"別責"};
  }
}

function deriveSanChuan(siKe, tianPan, dayGan, dayZhi) {
  return getSanChuan(siKe, tianPan, dayGan, dayZhi);
}

// 空亡
function kongWang(dayGanIdx, dayZhiIdx) {
  const xunIdx = GZ_IDX(dayGanIdx, dayZhiIdx);
  const xunStart = xunIdx - (xunIdx%10);
  const startZhi = xunStart%12;
  const kw1 = DI_ZHI[(startZhi+10)%12];
  const kw2 = DI_ZHI[(startZhi+11)%12];
  return [kw1, kw2];
}

// 十二天將
const TIAN_JIANG = ["貴人","螣蛇","朱雀","六合","勾陳","青龍","天空","白虎","太常","玄武","太陰","天后"];
function assignTianJiang(dayGanIdx, shiZhiIdx) {
  const GUI_REN = {0:1,1:0,2:11,3:11,4:1,5:0,6:1,7:6,8:5,9:5};
  const guiPos = GUI_REN[dayGanIdx];
  const isDay = shiZhiIdx>=0 && shiZhiIdx<=5;
  const nightPos = [1,0,11,11,1,0,1,6,5,5];
  const startPos = isDay ? guiPos : nightPos[dayGanIdx];
  const forward = isDay;
  const result = {};
  for(let i=0;i<12;i++){
    const pos = forward ? (startPos+i)%12 : ((startPos-i)%12+12)%12;
    result[DI_ZHI[pos]] = TIAN_JIANG[i];
  }
  return result;
}

// 課格判斷
function judgeKeGe(siKe, sanChuan, dayGan) {
  const patterns = [];
  const {chu,zhong,mo} = sanChuan;
  // 元首
  if(sanChuan.method==="賊克法"||sanChuan.method==="賊克法（上克下）") patterns.push("元首課");
  // 三傳遞生
  if(WX_SHENG[zhiWx(chu)]===zhiWx(zhong) && WX_SHENG[zhiWx(zhong)]===zhiWx(mo)) patterns.push("三傳遞生");
  // 三傳遞克
  if(WX_KE[zhiWx(chu)]===zhiWx(zhong) && WX_KE[zhiWx(zhong)]===zhiWx(mo)) patterns.push("三傳遞克");
  // 三傳皆同
  if(chu===zhong && zhong===mo) patterns.push("三傳皆同（獨足課）");
  return patterns.length?patterns:["待定"];
}

// 大六壬完整起課
function castLiuRen(date, question="") {
  const y=date.getFullYear(), m=date.getMonth()+1, d=date.getDate(), h=date.getHours();
  const jq = [...getJieqiDates(y>1900?y-1:y),...getJieqiDates(y),...getJieqiDates(y+1)].sort((a,b)=>a.jd-b.jd);
  const dayIdx = dayPillarIndex(y,m,d);
  const dayGanIdx = dayIdx%10, dayZhiIdx = dayIdx%12;
  const dayGan = TIAN_GAN[dayGanIdx], dayZhi = DI_ZHI[dayZhiIdx];
  const shiZhiIdx = Math.floor((h+1)/2)%12;
  const shiGanBase = (dayGanIdx%5)*2;
  const shiGanIdx = (shiGanBase+shiZhiIdx)%10;
  const shiGan = TIAN_GAN[shiGanIdx], shiZhi = DI_ZHI[shiZhiIdx];
  const yueJiang = getYueJiang(jq, date);
  const tianPan = buildTianDiPan(yueJiang, shiZhi);
  const siKe = buildSiKe(dayGan, dayZhi, tianPan);
  const sanChuan = deriveSanChuan(siKe, tianPan, dayGan, dayZhi);
  const kw = kongWang(dayGanIdx, dayZhiIdx);
  const tianJiang = assignTianJiang(dayGanIdx, shiZhiIdx);
  const keGe = judgeKeGe(siKe, sanChuan, dayGan);
  // 五行旺衰
  const season = m>=2&&m<=4?"春":m>=5&&m<=7?"夏":m>=8&&m<=10?"秋":"冬";
  const wxWang = {春:"木",夏:"火",秋:"金",冬:"水"};
  return {
    dayGan, dayZhi, shiGan, shiZhi, yueJiang,
    tianPan, siKe, sanChuan, kongWang:kw,
    tianJiang, keGe, season, wxWang:wxWang[season],
    question, date, dayGanIdx, dayZhiIdx
  };
}

