function qmGetJu(date, jieqiDates) {
  let currentJq = null;
  const sorted = [...jieqiDates].sort((a,b)=>a.jd-b.jd);
  for(let i=sorted.length-1;i>=0;i--){
    if(date >= sorted[i].date){ currentJq = sorted[i]; break; }
  }
  if(!currentJq) return {dun:1,ju:1,jqName:"冬至",yuan:"上"};
  const jqName = currentJq.name;
  const juData = QM_JU_DATA[jqName]||[1,1,7,4];
  // 拆補法定元：符頭＝最近的甲/己日（五日一符頭）
  const dayIdx = dayPillarIndex(date.getFullYear(), date.getMonth()+1, date.getDate());
  const fuTou = dayIdx - (dayIdx % 5);
  const fuTouBranch = fuTou % 12;
  // 上中下元: 子午卯酉→上, 寅申巳亥→中, 辰戌丑未→下
  const yuanMap = {0:1,6:1,3:1,9:1, 2:2,8:2,5:2,11:2, 4:3,10:3,1:3,7:3};
  const yuanIdx = yuanMap[fuTouBranch]||1;
  const yuanNames = ["","上","中","下"];
  return {dun:juData[0], ju:juData[yuanIdx], jqName, yuan:yuanNames[yuanIdx]};
}

function qmPaipan(date, options={}) {
  const y=date.getFullYear(), m=date.getMonth()+1, d=date.getDate(), h=date.getHours(), mi=date.getMinutes();
  let adjH=h, adjD=d;
  if(options.trueSolar && options.longitude) {
    const corr = (options.longitude-120)*4;
    const totalMin = h*60+mi+corr;
    adjH = Math.floor(((totalMin%1440)+1440)%1440/60);
    if(totalMin<0) adjD=d-1;
    if(totalMin>=1440) adjD=d+1;
  }
  const jq = [...getJieqiDates(y>1900?y-1:y),...getJieqiDates(y),...getJieqiDates(y+1)].sort((a,b)=>a.jd-b.jd);
  const {dun,ju,jqName,yuan} = qmGetJu(date, jq);
  const dayIdx = dayPillarIndex(y,m,adjD<1?d:adjD);
  const dayGanIdx = dayIdx%10, dayZhiIdx = dayIdx%12;
  const shiZhiIdx = Math.floor((adjH+1)/2)%12;
  const shiGanBase = (dayGanIdx%5)*2;
  const shiGanIdx = (shiGanBase+shiZhiIdx)%10;
  // 時干支六十甲子序數
  const shiSixty = GZ_IDX(shiGanIdx, shiZhiIdx);
  const shiXunStart = shiSixty - (shiSixty%10);
  const shiYi = QM_YI_OF_XUN[shiXunStart]||"戊";
  // ===== 九宮初始化 =====
  const palaces = {};
  for(let p=1;p<=9;p++) palaces[p]={palace:p,name:QM_PALACE_NAME[p],elem:QM_PALACE_ELEM[p],diGan:"",tianGan:"",tianGanJi:"",star:"",door:"",god:"",markers:[]};

  // ===== 地盤：戊起局宮，按宮數順序（陽順陰逆），九宮全排 =====
  const stemSeq = ["戊","己","庚","辛","壬","癸","丁","丙","乙"];
  for(let i=0;i<9;i++){
    const p = dun===1 ? ((ju-1+i)%9)+1 : (((ju-1-i)%9)+9)%9+1;
    palaces[p].diGan = stemSeq[i];
  }

  // 中宮寄坤二
  const ji = p => p===5 ? 2 : p;
  const cIdx = p => QM_CIRCLE.indexOf(ji(p));

  // ===== 值符星 / 值使門：旬首六儀所在地盤宮 =====
  let yiPalace = 0;
  for(let p=1;p<=9;p++){ if(palaces[p].diGan===shiYi){yiPalace=p;break;} }
  if(!yiPalace) yiPalace = ju;
  const zhiFuStar = QM_STARS[yiPalace];
  const zhiShiDoor = QM_DOORS[ji(yiPalace)]||"死門";

  // ===== 時干落宮（甲遁六儀） =====
  const shiGanStr = QM_STEMS[shiGanIdx];
  let shiGanPalace = 0;
  if(shiGanStr==="甲"){ shiGanPalace = yiPalace; }
  else { for(let p=1;p<=9;p++){ if(palaces[p].diGan===shiGanStr){shiGanPalace=p;break;} } }
  if(!shiGanPalace) shiGanPalace = yiPalace;

  // ===== 天盤+九星：值符隨時干轉動 =====
  const shift = ((cIdx(shiGanPalace)-cIdx(yiPalace))%8+8)%8;
  for(let i=0;i<8;i++){
    const fromP = QM_CIRCLE[i];
    const toP = QM_CIRCLE[(i+shift)%8];
    palaces[toP].tianGan = palaces[fromP].diGan;
    palaces[toP].star = QM_STARS[fromP];
    if(fromP===2) palaces[toP].tianGanJi = palaces[5].diGan; // 中宮干寄坤二隨行
  }
  palaces[5].tianGan = "";
  palaces[5].star = "天禽";

  // ===== 八門：值使門從值符宮按時辰數飛佈 =====
  const steps = shiSixty - shiXunStart; // 旬內第幾時辰 (0-9)
  let zsLand = dun===1 ? ((yiPalace-1+steps)%9)+1 : (((yiPalace-1-steps)%9)+9)%9+1;
  const zsLandJi = ji(zsLand);
  const zsDoorIdx = QM_DOOR_CIRCLE.indexOf(zhiShiDoor);
  const zsLandC = cIdx(zsLandJi);
  for(let i=0;i<8;i++){
    palaces[QM_CIRCLE[(zsLandC+i)%8]].door = QM_DOOR_CIRCLE[(zsDoorIdx+i)%8];
  }

  // ===== 八神：從值符落宮起，陽順陰逆 =====
  const zfLandC = cIdx(shiGanPalace);
  for(let i=0;i<8;i++){
    const p = dun===1 ? QM_CIRCLE[(zfLandC+i)%8] : QM_CIRCLE[((zfLandC-i)%8+8)%8];
    palaces[p].god = QM_GODS_LIST[i];
  }
  // 空亡
  const kw = kongWang(dayGanIdx, dayZhiIdx);
  // 標記（增強版）
  for(let p=1;p<=9;p++){
    const marks = [];
    if(palaces[p].tianGan===palaces[p].diGan) marks.push("伏吟");
    // 反吟：天盤干在原始地盤的對宮
    if(palaces[p].tianGan && palaces[p].diGan) {
      let tianOrigP=0; for(let q=1;q<=9;q++){if(q!==p && palaces[q].diGan===palaces[p].tianGan){tianOrigP=q;break;}}
      const opp={1:9,9:1,3:7,7:3,2:8,8:2,4:6,6:4};
      if(tianOrigP && opp[tianOrigP]===p) marks.push("反吟");
    }
    if(palaces[p].god==="值符") marks.push("值符");
    if(palaces[p].door===zhiShiDoor && p===QM_CIRCLE[zsLandC%8]) marks.push("值使");
    // 門迫：宮克門
    const doorElem = QM_DOOR_ELEM[palaces[p].door];
    if(doorElem && WX_KE[QM_PALACE_ELEM[p]]===doorElem) marks.push("門迫");
    // 空亡宮：宮對應地支落入空亡
    const pZhi = QM_PALACE_ZHI[p]||[];
    if(pZhi.some(z=>kw.includes(z))) marks.push("空亡");
    // 奇儀格局
    const combo = palaces[p].tianGan+"+"+palaces[p].diGan;
    if(QM_QIYI_COMBO[combo]) palaces[p].combo = QM_QIYI_COMBO[combo];
    palaces[p].markers = marks;
  }
  return {
    palaces, dun, ju, yuan, jqName,
    dayGan:QM_STEMS[dayGanIdx], dayZhi:QM_BRANCHES[dayZhiIdx],
    shiGan:QM_STEMS[shiGanIdx], shiZhi:QM_BRANCHES[shiZhiIdx],
    zhiFuStar, zhiShiDoor, kongWang:kw,
    dayGz:SIXTY[dayIdx], shiGz:QM_STEMS[shiGanIdx]+QM_BRANCHES[shiZhiIdx],
    question: options.question||""
  };
}

