function buildBaziPrompt(bazi, gender, birthStr) {
  const lines = [
    "你是精通八字命理的術數大師，學識淵博。請用繁體中文進行完整專業分析。以下是命主的八字資料：",
    "",
    "【命主資料】",
    "出生：" + birthStr,
    "性別：" + gender,
    "",
    "【四柱八字】",
    "年柱：" + bazi.year.gz + "　月柱：" + bazi.month.gz,
    "日柱：" + bazi.day.gz + "　時柱：" + bazi.hour.gz,
    "",
    "【日主】" + bazi.dayGan + "（" + wxOf(bazi.dayGan) + "）",
    "",
    "【十神配置】",
    "年干 " + bazi.year.gan + " = " + tenGod(bazi.dayGan, bazi.year.gan),
    "月干 " + bazi.month.gan + " = " + tenGod(bazi.dayGan, bazi.month.gan),
    "時干 " + bazi.hour.gan + " = " + tenGod(bazi.dayGan, bazi.hour.gan),
    "",
    "【藏干十神】"
  ];
  ["year","month","day","hour"].forEach(p=>{
    const pn=p==="year"?"年支":p==="month"?"月支":p==="day"?"日支":"時支";
    const zhi = bazi[p].zhi;
    const cang = ZHI_CANG[zhi]||[];
    lines.push(pn + " " + zhi + " 藏：" + cang.map(g=>g+"("+tenGod(bazi.dayGan,g)+")").join("、"));
  });
  lines.push("", "【長生十二宮】");
  ["year","month","day","hour"].forEach(p=>{
    const pn=p==="year"?"年支":p==="month"?"月支":p==="day"?"日支":"時支";
    lines.push(pn + " " + bazi[p].zhi + " → " + getChangSheng(bazi.dayGan, bazi[p].zhi));
  });
  const rels = analyzeGanZhiRelations(bazi);
  if(rels.length) lines.push("", "【干支關係】" + rels.map(r=>r.desc).join("、"));
  if(bazi.shensha.length) lines.push("", "【神煞】" + bazi.shensha.join("、"));
  lines.push("","請以約5000字進行深入但易懂的分析，語氣直接實用，避免過多術語堆砌：","1. 日主旺衰判定（結合月令、藏干、長生狀態）","2. 格局分析","3. 用神喜忌","4. 五行調候","5. 性格特質與為人","6. 事業方向與財運","7. 感情婚姻","8. 健康注意","9. 大運走勢（逐步分析每步大運重點）","10. 近年流年提示與具體建議");
  return lines.join("\n");
}

// 六親（大六壬）
function liuQin(dayGan, zhi) {
  const dWx = wxOf(dayGan), zWx = zhiWx(zhi);
  if(dWx===zWx) return "兄弟";
  if(WX_SHENG[dWx]===zWx) return "子孫";
  if(WX_KE[dWx]===zWx) return "妻財";
  if(WX_KE[zWx]===dWx) return "官鬼";
  if(WX_SHENG[zWx]===dWx) return "父母";
  return "";
}
