function buildLiuRenPrompt(result) {
  const lines = [
    "你是精通大六壬的術數大師，學識淵博。請用繁體中文進行完整專業斷課分析。",
    ""
  ];
  if(result.question) lines.push("【問事】" + result.question, "");
  lines.push(
    "【基本資訊】",
    "日干支：" + result.dayGan + result.dayZhi + "　占時：" + result.shiGan + result.shiZhi,
    "月將：" + result.yueJiang + "　當令：" + result.season + "（" + result.wxWang + "旺）",
    "取傳法：" + result.sanChuan.method,
    "空亡：" + result.kongWang.join("、"),
    "課格：" + result.keGe.join("、"),
    "",
    "【四課】"
  );
  result.siKe.forEach(k=>{
    const tj = result.tianJiang[k.shang]||"";
    const lq = liuQin(result.dayGan, k.shang);
    const ke = wxKe(k.shang,k.xia)?"上克下":wxKe(k.xia,k.shang)?"下克上（賊）":"無克";
    lines.push(k.label + "：上" + k.shang + "("+lq+") 下" + k.xia + " 天將:" + tj + " 克應:" + ke);
  });
  lines.push("", "【三傳】");
  ["初傳","中傳","末傳"].forEach((name,i) => {
    const val = [result.sanChuan.chu,result.sanChuan.zhong,result.sanChuan.mo][i];
    const lq = liuQin(result.dayGan, val);
    const tj = result.tianJiang[val]||"";
    const empty = result.kongWang.includes(val)?"（空亡）":"";
    lines.push(name + "：" + val + " " + lq + " 天將:" + tj + " " + empty);
  });
  lines.push("","【天地盤】");
  DI_ZHI.forEach(z=>lines.push("地"+z+"→天"+result.tianPan[z]));
  lines.push("","請以約5000字進行深入但易懂的斷課分析，語氣直接實用：","1. 課式格局總判（課名含義及整體吉凶）","2. 四課主客分析（一二課=我方，三四課=對方）","3. 三傳脈絡（初傳起因→中傳發展→末傳結果）","4. 六親分析（各傳六親對應人事）","5. 天將配合解讀","6. 空亡影響","7. 五行旺衰與當令","8. 綜合判斷與具體行動建議");
  return lines.join("\n");
}

function buildQimenPrompt(result) {
  const lines = [
    "你是精通奇門遁甲的術數大師。請用繁體中文進行完整分析。",
    ""
  ];
  if(result.question) lines.push("【問事】" + result.question, "");
  lines.push(
    "【基本資訊】",
    (result.dun===1?"陽":"陰") + "遁" + result.ju + "局",
    "節氣：" + result.jqName + "　" + result.yuan + "元",
    "日柱：" + result.dayGz + "　時柱：" + result.shiGz,
    "值符：" + result.zhiFuStar + "　值使：" + result.zhiShiDoor,
    "空亡：" + result.kongWang.join("、"),
    "",
    "【九宮排盤】"
  );
  for(let p=1;p<=9;p++){
    const pa = result.palaces[p];
    if(pa) {
      let line = pa.name + "：天盤" + (pa.tianGan||"-") + (pa.tianGanJi?"(寄"+pa.tianGanJi+")":"") + " 地盤" + (pa.diGan||"-") + " " + pa.star + " " + (pa.door||"-") + " " + (pa.god||"-");
      if(pa.combo) line += " 【" + pa.combo + "】";
      if(pa.markers.length) line += " [" + pa.markers.join(",") + "]";
      lines.push(line);
    }
  }
  lines.push("","請以約5000字進行深入但易懂的分析，語氣直接實用：","1. 值符值使判斷","2. 天盤地盤奇儀組合格局","3. 星門神組合解讀","4. 用神分析（問事對應宮位）","5. 吉凶判斷（門迫、空亡、伏吟、反吟）","6. 行動建議與擇時方向");
  return lines.join("\n");
}

