function AdminPanel({ onExit, currentUserId }) {
  const [users, setUsers] = useState([]);
  const [stats, setStats] = useState({ total:0, vip:0, freeToday:0, paidToday:0 });
  const [loading, setLoading] = useState(true);
  const [busy, setBusy] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    const [{ data:accounts, error:accountsError }, { data:profs, error:profilesError }] = await Promise.all([
      supabase.from("accounts").select("*").order("created_at",{ascending:false}),
      supabase.from("profiles").select("*"),
    ]);
    if (accountsError) throw accountsError;
    if (profilesError) throw profilesError;
    const today = new Date().toISOString().slice(0,10);
    const { data:usage } = await supabase.from("usage_daily").select("*").eq("day",today);
    const freeToday = (usage||[]).reduce((s,u)=>s+(u.free_count||0),0);
    const paidToday = (usage||[]).reduce((s,u)=>s+(u.paid_count||0),0);
    // 每人總用量
    const { data:allUsage } = await supabase.from("usage_daily").select("user_id,free_count,paid_count");
    const totalByUser = {};
    (allUsage||[]).forEach(u=>{ const t=totalByUser[u.user_id]||{f:0,p:0}; t.f+=u.free_count||0; t.p+=u.paid_count||0; totalByUser[u.user_id]=t; });
    const profileById = Object.fromEntries((profs||[]).map(p=>[p.id,p]));
    setUsers((accounts||[]).map(a=>({
      ...(profileById[a.id] || {}),
      ...a,
      tier:a.account_type,
      usage:totalByUser[a.id]||{f:0,p:0},
    })));
    setStats({ total:(accounts||[]).length, vip:(accounts||[]).filter(a=>a.account_type==="vip").length, freeToday, paidToday });
    setLoading(false);
  }, []);

  useEffect(()=>{ load(); }, [load]);

  const setTier = async (id, tier) => {
    setBusy(id);
    try {
      const { error } = await supabase.from("accounts")
        .update({ account_type:tier, updated_at:new Date().toISOString() })
        .eq("id", id);
      if (error) throw error;
      await load();
    } finally {
      setBusy(null);
    }
  };

  return (
    <div style={STYLES.app}>
      <header style={{...STYLES.header,background:"linear-gradient(135deg,#3a2818,#5a3a20)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",maxWidth:900,margin:"0 auto"}}>
          <h1 style={{...STYLES.title,fontSize:22}}>後台管理</h1>
          <button onClick={onExit} style={{fontSize:12,padding:"4px 14px",borderRadius:8,border:"1px solid #fff",background:"transparent",color:"#fff",cursor:"pointer"}}>返回</button>
        </div>
      </header>
      <main style={{maxWidth:900,margin:"0 auto",padding:16}}>
        {/* 統計卡 */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginBottom:16}}>
          {[["總用戶",stats.total,"#8b6914"],["VIP",stats.vip,"#DAA520"],["今日免費",stats.freeToday,"#228B22"],["今日付費",stats.paidToday,"#c23b22"]].map(([l,v,c],i)=>(
            <div key={i} style={{...STYLES.card,textAlign:"center",margin:0,background:"rgba(255,255,255,0.92)"}}>
              <div style={{fontSize:11,color:"#8a7a5a"}}>{l}</div>
              <div style={{fontSize:24,fontWeight:700,color:c}}>{v}</div>
            </div>
          ))}
        </div>
        <div style={{fontSize:11,color:"#8a7a5a",marginBottom:8,textAlign:"right"}}>
          今日成本估算 ≈ US${(stats.freeToday*0.001 + stats.paidToday*0.008).toFixed(3)}
        </div>

        {/* 用戶列表 */}
        {loading ? <div style={{textAlign:"center",padding:30,color:"#8a7a5a"}}>載入中…</div> : (
          <div style={{...STYLES.card,background:"rgba(255,255,255,0.94)",padding:0,overflow:"hidden"}}>
            <div style={{display:"grid",gridTemplateColumns:"1.5fr 1.1fr 1.5fr 0.6fr 0.8fr 1fr",gap:0,fontSize:11,fontWeight:700,color:"#8b6914",background:"#f5eed8",padding:"8px 10px"}}>
              <div>帳戶</div><div>稱呼</div><div>八字資料</div><div>性別</div><div>用量</div><div>等級</div>
            </div>
            {users.map(u=>(
              <div key={u.id} style={{display:"grid",gridTemplateColumns:"1.5fr 1.1fr 1.5fr 0.6fr 0.8fr 1fr",gap:0,fontSize:12,padding:"8px 10px",borderTop:"1px solid #f0ebe0",alignItems:"center"}}>
                <div style={{fontSize:10,color:"#5a4a2a",overflowWrap:"anywhere"}}>{u.email||"匿名訪客"}</div>
                <div style={{fontWeight:600}}>{u.display_name||"（未命名）"}</div>
                <div style={{fontSize:11,color:"#5a4a2a"}}>{u.birth_year?`${u.birth_year}/${u.birth_month}/${u.birth_day} ${String(u.birth_hour).padStart(2,"0")}:${String(u.birth_minute||0).padStart(2,"0")}`:"—"}</div>
                <div>{u.gender||"—"}</div>
                <div style={{fontSize:11}}><span style={{color:"#228B22"}}>{u.usage.f}</span>/<span style={{color:"#c23b22"}}>{u.usage.p}</span></div>
                <div>
                  <select
                    value={u.tier}
                    disabled={busy===u.id || u.id===currentUserId}
                    onChange={e=>setTier(u.id,e.target.value)}
                    style={{...STYLES.input,padding:"4px 6px",fontSize:11}}
                    title={u.id===currentUserId?"不能在這裡更改自己的管理員等級":"更改帳戶等級"}
                  >
                    <option value="guest">Guest</option>
                    <option value="vip">VIP</option>
                    <option value="admin">Admin</option>
                  </select>
                </div>
              </div>
            ))}
            {users.length===0 && <div style={{padding:20,textAlign:"center",color:"#b0a080",fontSize:12}}>暫無用戶</div>}
          </div>
        )}
      </main>
    </div>
  );
}

function OnboardingGate({ profile, onDone, onLogout }) {
  const [name, setName] = useState(profile?.display_name||"");
  const [by, setBy] = useState(profile?.birth_year||"");
  const [bm, setBm] = useState(profile?.birth_month||"");
  const [bd, setBd] = useState(profile?.birth_day||"");
  const [bh, setBh] = useState(profile?.birth_hour??12);
  const [bmi, setBmi] = useState(profile?.birth_minute??0);
  const [gender, setGender] = useState(profile?.gender||"男");
  const [lng, setLng] = useState(profile?.longitude||"114.17");
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");

  const submit = async () => {
    if(!by||!bm||!bd){ setErr("請填寫完整出生年月日"); return; }
    setSaving(true); setErr("");
    try {
      await saveProfile({ display_name:name, birth_year:+by, birth_month:+bm, birth_day:+bd,
        birth_hour:+bh, birth_minute:+bmi, gender, longitude:parseFloat(lng)||114.17 });
      onDone();
    } catch(e) { setErr("儲存失敗："+e.message); }
    setSaving(false);
  };

  return (
    <div style={STYLES.app}>
      <header style={STYLES.header}>
        <div style={{fontSize:11,color:"#e8d8a8",letterSpacing:"0.5em"}}>中華術數</div>
        <h1 style={STYLES.title}>卦來卦去</h1>
      </header>
      <main style={{maxWidth:460,margin:"0 auto",padding:"16px"}}>
        <div style={{...STYLES.card,background:"rgba(255,255,255,0.92)"}}>
          <div style={{fontSize:16,fontWeight:700,color:"#8b6914",marginBottom:4}}>建立個人資料</div>
          <div style={{fontSize:12,color:"#8a7a5a",marginBottom:12}}>首次使用請填寫出生資料（只需一次），日後占卜可另開新盤。</div>
          <div style={{marginBottom:8}}>
            <label style={STYLES.label}>稱呼</label>
            <input value={name} onChange={e=>setName(e.target.value)} placeholder="你的稱呼" style={STYLES.input} />
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:8}}>
            <div><label style={STYLES.label}>年</label><input type="number" value={by} onChange={e=>setBy(e.target.value)} placeholder="1990" style={STYLES.input}/></div>
            <div><label style={STYLES.label}>月</label><select value={bm} onChange={e=>setBm(e.target.value)} style={STYLES.input}><option value="">-</option>{[...Array(12)].map((_,i)=><option key={i} value={i+1}>{i+1}月</option>)}</select></div>
            <div><label style={STYLES.label}>日</label><select value={bd} onChange={e=>setBd(e.target.value)} style={STYLES.input}><option value="">-</option>{[...Array(31)].map((_,i)=><option key={i} value={i+1}>{i+1}日</option>)}</select></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:8}}>
            <div><label style={STYLES.label}>時 (0-23)</label><input type="number" value={bh} onChange={e=>setBh(e.target.value)} style={STYLES.input} min="0" max="23"/></div>
            <div><label style={STYLES.label}>分</label><input type="number" value={bmi} onChange={e=>setBmi(e.target.value)} style={STYLES.input} min="0" max="59"/></div>
            <div><label style={STYLES.label}>性別</label><select value={gender} onChange={e=>setGender(e.target.value)} style={STYLES.input}><option>男</option><option>女</option></select></div>
          </div>
          {err && <div style={{fontSize:12,color:"#c23b22",marginBottom:8}}>{err}</div>}
          <button onClick={submit} disabled={saving} style={{...STYLES.btn(true),width:"100%",opacity:saving?0.6:1}}>{saving?"儲存中…":"完成，開始使用"}</button>
          {onLogout && <button onClick={onLogout} disabled={saving} style={{...STYLES.btnSmall,width:"100%",marginTop:8}}>登出／使用其他帳戶</button>}
        </div>
      </main>
    </div>
  );
}

export default function App() {
  const [activeTab, setActiveTab] = useState("bazi");
  const [authReady, setAuthReady] = useState(false);
  const [session, setSession] = useState(null);
  const [profile, setProfile] = useState(null);
  const [account, setAccount] = useState(null);
  const [needOnboard, setNeedOnboard] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [showAccount, setShowAccount] = useState(false);
  const [passwordRecovery, setPasswordRecovery] = useState(
    () => window.location.hash.includes("type=recovery")
  );

  const loadAccount = useCallback(async (nextSession) => {
    setSession(nextSession || null);
    setShowAccount(false);
    setShowAdmin(false);
    if (!nextSession) {
      setProfile(null);
      setAccount(null);
      setNeedOnboard(false);
      setAuthReady(true);
      return;
    }

    try {
      await ensureAccount();
      const [prof, acct] = await Promise.all([getProfile(), getAccount()]);
      setProfile(prof);
      setAccount(acct);
      setNeedOnboard(!prof?.birth_year);
    } catch (e) {
      console.error(e);
      setProfile(null);
      setAccount(null);
      setNeedOnboard(true);
    }
    setAuthReady(true);
  }, []);

  useEffect(() => {
    if (!isSupabaseConfigured) {
      setAuthReady(true);
      return;
    }
    let mounted = true;
    setAuthReady(false);

    supabase.auth.getSession().then(({ data }) => {
      if (mounted) loadAccount(data.session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, nextSession) => {
      if (event === "PASSWORD_RECOVERY") setPasswordRecovery(true);
      window.setTimeout(() => {
        if (mounted) loadAccount(nextSession);
      }, 0);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, [loadAccount]);

  const handleAuthenticated = useCallback(async (nextSession) => {
    if (nextSession) {
      await loadAccount(nextSession);
      return;
    }
    const { data } = await supabase.auth.getSession();
    await loadAccount(data.session);
  }, [loadAccount]);

  const tabs = [
    {id:"bazi",label:"八字命理",icon:"命"},
    {id:"liuren",label:"大六壬",icon:"壬"},
    {id:"qimen",label:"奇門遁甲",icon:"奇"}
  ];

  if (!isSupabaseConfigured) return (
    <div style={{...STYLES.app,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{...STYLES.card,width:"100%",maxWidth:520,textAlign:"center",background:"rgba(255,255,255,0.94)"}}>
        <h1 style={{fontSize:22,color:"#8b6914",margin:"0 0 10px"}}>尚欠 Supabase 設定</h1>
        <p style={{fontSize:13,color:"#6a5a3a",lineHeight:1.7,margin:"0 0 12px"}}>
          請在專案的 .env 加入以下兩項，儲存後重新啟動網站：
        </p>
        <div style={{fontFamily:"monospace",fontSize:12,textAlign:"left",padding:12,borderRadius:8,background:"#f5eed8",color:"#5a4a2a",overflowWrap:"anywhere"}}>
          VITE_SUPABASE_URL=你的_Project_URL<br />
          VITE_SUPABASE_ANON_KEY=你的_anon_public_key
        </div>
      </div>
    </div>
  );

  if (!authReady) return (
    <div style={{...STYLES.app,display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{color:"#8b6914",fontSize:16,fontFamily:"'Noto Serif TC',serif"}}>載入中…</div>
    </div>
  );

  if (passwordRecovery && session) return <PasswordRecovery onDone={()=>setPasswordRecovery(false)} />;

  if (!session) return <AuthGate onAuthenticated={handleAuthenticated} />;

  if (needOnboard) return <OnboardingGate profile={profile} onDone={async()=>{ setProfile(await getProfile()); setNeedOnboard(false); }} onLogout={async()=>{ await supabase.auth.signOut(); }} />;

  if (showAdmin && account?.account_type==="admin") return <AdminPanel currentUserId={session.user.id} onExit={()=>setShowAdmin(false)} />;

  if (showAccount) return (
    <AccountPanel
      user={session.user}
      profile={profile}
      account={account}
      onClose={()=>setShowAccount(false)}
      onProfileSaved={async()=>setProfile(await getProfile())}
      onLoggedOut={()=>loadAccount(null)}
    />
  );

  return (
    <div style={STYLES.app}>
      <header style={STYLES.header}>
        <div style={{fontSize:11,color:"#e8d8a8",letterSpacing:"0.5em",textShadow:"0 1px 6px rgba(0,0,0,0.6)"}}>中華術數</div>
        <h1 style={STYLES.title}>卦來卦去</h1>
        <div style={STYLES.subtitle}>八字 ・ 大六壬 ・ 奇門遁甲</div>
        <div style={{marginTop:6,display:"flex",gap:8,justifyContent:"center",alignItems:"center"}}>
          <span style={{fontSize:11,padding:"2px 10px",borderRadius:10,background:account?.account_type==="vip"?"#DAA520":account?.account_type==="admin"?"#c23b22":"rgba(255,255,255,0.25)",color:"#fff",fontWeight:600}}>
            {account?.account_type==="vip"?"VIP 會員":account?.account_type==="admin"?"管理員":session.user.is_anonymous?"訪客":"Guest 會員"}
          </span>
          <button onClick={()=>setShowAccount(true)} style={{fontSize:11,padding:"2px 10px",borderRadius:10,border:"1px solid #fff",background:"transparent",color:"#fff",cursor:"pointer"}}>我的帳戶</button>
          {account?.account_type==="admin" && <button onClick={()=>setShowAdmin(true)} style={{fontSize:11,padding:"2px 10px",borderRadius:10,border:"1px solid #fff",background:"transparent",color:"#fff",cursor:"pointer"}}>後台</button>}
        </div>
      </header>

      <nav style={STYLES.nav}>
        {tabs.map(t => (
          <button key={t.id} onClick={()=>setActiveTab(t.id)} style={STYLES.navBtn(activeTab===t.id)}>
            <span style={{fontSize:18,display:"block"}}>{t.icon}</span>
            <span style={{fontSize:11}}>{t.label}</span>
          </button>
        ))}
      </nav>

      <main style={{maxWidth:780,margin:"0 auto",paddingBottom:40}}>
        {activeTab==="bazi" && <BaziModule profile={profile} />}
        {activeTab==="liuren" && <LiuRenModule userTier={account?.account_type} />}
        {activeTab==="qimen" && <QimenModule userTier={account?.account_type} />}
      </main>

      <footer style={{textAlign:"center",padding:"20px 16px",fontSize:11,color:"#b0a080",borderTop:"1px solid #e8dcc4"}}>
        卦來卦去 — 傳統中華術數工具集
      </footer>
    </div>
  );
}
